-- 1. JSON 유효성 검사 및 데이터 저장
CREATE TABLE user_profiles (
    id INT AUTO_INCREMENT PRIMARY KEY,
    data LONGTEXT,
    CONSTRAINT CHECK (JSON_VALID(data))
);

-- 2. JSON 데이터 조회
SELECT data->>'$.name' AS name FROM user_profiles;

-- 3. 기존 컬럼 결합하여 JSON 생성
SELECT JSON_OBJECT('id', id, 'name', name) AS json_data FROM users;
